// Curated Australian mental-health + healthcare reference data.
//
// Phase R follow-up (2026-04-18). Single source of truth for 8 categories
// of seedable reference data. Consumed by:
//
//   apps/api/src/features/provisioning/provisioningService.ts
//     — for new-clinic provisioning (inserts on first tenant creation)
//
//   apps/api/src/seed-good-health/generators/00_reference_data.ts
//     — for the Good Health demo seed (upserts against ALL active clinics,
//       idempotent via deterministic uuidv5 ids)
//
// Every row below carries a `sourceUrl` citing a primary Australian
// source (AHPRA, MBS Online, state health departments, peak bodies).
// Curation pass: 2026-04-18 by 3 parallel research agents.
//
// Do NOT duplicate this data anywhere else. If you need a new category,
// add a new const array here and register it in both consumers in the
// same commit.

export interface AuReferenceRow {
  /** kebab-case stable id — used as the uuidv5 seed so reseeds upsert in place. */
  slug: string;
  /** Display name shown to clinicians in dropdowns. Mapped to DB `name` column. */
  displayName: string;
  /** One-sentence description, for tooltip/docs. NOT persisted to DB `name` table by default. */
  description: string;
  /** 0-based sort index. Mapped to DB `sort_order`. */
  sortOrder: number;
  /** URL to an authoritative Australian primary source citing this row. */
  sourceUrl: string;
  /** Category-specific metadata — see per-array type definitions below. */
  metadata: Record<string, unknown>;
}

